./tools/db.py<pre><code>from strands import tool
import sqlite3
from pathlib import Path

@tool
def query_db(sql: str) -&gt; str:
    """Run a read-only SQL query on ./data.db. Returns up to 50 rows."""
    db = Path("data.db")
    if not db.exists():
        return "error: data.db not found in cwd"
    with sqlite3.connect(f"file:{db}?mode=ro", uri=True) as conn:
        try:
            rows = conn.execute(sql).fetchall()
            if not rows:
                return "(no rows)"
            return "\n".join(str(r) for r in rows[:50])
        except sqlite3.Error as e:
            return f"sql error: {e}"
</code></pre> <pre><code>do "how many users signed up last week?"
# → agent writes SQL, calls query_db, formats the answer
</code></pre>

./tools/http.py<pre><code>from strands import tool
import urllib.request, json

@tool
def http_get(url: str, accept: str = "application/json") -&gt; str:
    """GET a URL. Returns the body as text (truncated to 10KB)."""
    req = urllib.request.Request(url, headers={"Accept": accept})
    with urllib.request.urlopen(req, timeout=10) as r:
        return r.read(10_000).decode("utf-8", errors="replace")
